import java.util.*;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int first = scanner.nextInt();
        int last = first;
        for (int i = 1; i < n; i++) {
            last = scanner.nextInt();
        }
        System.out.println(n == 1 ? first : first + last);
    }
}
